import sys
from itertools import combinations
from functools import lru_cache

def main():
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    cards = [(int(data[i*2+1]), int(data[i*2+2])) for i in range(N)]

    @lru_cache(maxsize=None)
    def game_state(mask):
        # Find all possible pairs
        possible_moves = []
        for i in range(N):
            if not (mask & (1 << i)):
                continue
            for j in range(i + 1, N):
                if not (mask & (1 << j)):
                    continue
                if cards[i][0] == cards[j][0] or cards[i][1] == cards[j][1]:
                    new_mask = mask & ~((1 << i) | (1 << j))
                    possible_moves.append(new_mask)
        # If no moves, current player loses
        if not possible_moves:
            return False
        # Current player wins if any move leads to opponent losing
        for move in possible_moves:
            if not game_state(move):
                return True
        return False

    initial_mask = (1 << N) - 1
    if game_state(initial_mask):
        print("Takahashi")
    else:
        print("Aoki")

main()
